const fs=require("fs");const path=require("path");const RESPONSES_DIR=".temp/coordination/cross-tool/responses";const REVIEWS_DIR=".claude/gemini-bridge/reviews";const STATE_FILE=".temp/coordination/cross-tool/handoff-state.json";const BATCH_WINDOW_MS=5*60*1e3;function run(){try{if(!fs.existsSync(RESPONSES_DIR))return;let state={processed_files:[],last_check:null};if(fs.existsSync(STATE_FILE)){try{state=JSON.parse(fs.readFileSync(STATE_FILE,"utf8"));state.processed_files=state.processed_files||[]}catch(e){state={processed_files:[],last_check:null}}}const files=fs.readdirSync(RESPONSES_DIR).filter(f=>f.endsWith(".json")||f.endsWith(".md")).map(f=>{const filePath=path.join(RESPONSES_DIR,f);const stat=fs.statSync(filePath);return{name:f,path:filePath,size:stat.size,mtimeMs:stat.mtimeMs}}).sort((a,b)=>a.name.localeCompare(b.name));if(files.length===0)return;const unread=files.filter(f=>!state.processed_files.includes(f.name));if(unread.length===0)return;const batches=groupIntoBatches(unread,BATCH_WINDOW_MS);const isParallelRun=unread.length>=2&&batches.some(b=>b.length>=2);console.log("\n╔══════════════════════════════════════════╗");if(isParallelRun){console.log("║   GEMINI 병렬 분석 결과 대기 중          ║")}else{console.log("║   GEMINI 분석 결과 대기 중               ║")}console.log("╚══════════════════════════════════════════╝");if(isParallelRun){console.log(`\n미처리 Gemini 보고서 ${unread.length}개 발견 (${batches.length}개 배치):\n`);batches.forEach((batch,batchIdx)=>{const batchTime=new Date(batch[0].mtimeMs).toLocaleTimeString("ko-KR");console.log(`  [배치 ${batchIdx+1}] ${batchTime} — ${batch.length}개 파일`);batch.forEach((file,i)=>{const sizeKb=(file.size/1024).toFixed(1);const taskType=detectTaskType(file.name);console.log(`    ${i+1}. [${taskType}] ${file.name} (${sizeKb}KB)`)});console.log("")})}else{console.log(`\n미처리 Gemini 보고서 ${unread.length}개 발견:\n`);unread.forEach((file,i)=>{const sizeKb=(file.size/1024).toFixed(1);const taskType=detectTaskType(file.name);console.log(`  ${i+1}. [${taskType}] ${file.name} (${sizeKb}KB)`)})}console.log("처리 방법:");console.log("  /gemini-handoff read  → 최신 결과 읽고 실행 계획 수립");if(isParallelRun){console.log("  (병렬 실행 결과 — 일괄 처리 권장)")}console.log("──────────────────────────────────────────────\n")}catch(error){}try{if(!fs.existsSync(REVIEWS_DIR))return;const reviewFiles=fs.readdirSync(REVIEWS_DIR).filter(f=>f.endsWith(".json")).map(f=>{const filePath=path.join(REVIEWS_DIR,f);try{const data=JSON.parse(fs.readFileSync(filePath,"utf8"));return{name:f,path:filePath,data:data}}catch(_){return null}}).filter(Boolean);const unshown=reviewFiles.filter(f=>f.data.status==="completed");if(unshown.length===0)return;console.log("\n╔══════════════════════════════════════════╗");console.log("║   GEMINI REVIEW 결과 대기 중             ║");console.log("╚══════════════════════════════════════════╝");console.log(`\n미확인 리뷰 ${unshown.length}건:\n`);unshown.forEach((f,i)=>{const d=f.data;const icon=d.needsAttention?"⚠️ ":"✅";const type=d.scanType||"review";const issueCount=(d.issues||[]).length;const critical=(d.issues||[]).filter(x=>x.severity==="critical").length;console.log(`  ${icon} ${i+1}. [${type.toUpperCase()}] ${f.name}`);if(issueCount>0){console.log(`     이슈 ${issueCount}건 (critical: ${critical})`);(d.issues||[]).filter(x=>x.severity==="critical").slice(0,3).forEach(issue=>{console.log(`     🔴 ${issue.text}`)})}if(d.verdict)console.log(`     verdict: ${d.verdict}`)});console.log("\n──────────────────────────────────────────────\n")}catch(_){}}function groupIntoBatches(files,windowMs){if(files.length===0)return[];const sorted=[...files].sort((a,b)=>a.mtimeMs-b.mtimeMs);const batches=[];let currentBatch=[sorted[0]];for(let i=1;i<sorted.length;i++){const prev=sorted[i-1];const curr=sorted[i];if(curr.mtimeMs-prev.mtimeMs<=windowMs){currentBatch.push(curr)}else{batches.push(currentBatch);currentBatch=[curr]}}batches.push(currentBatch);return batches}function detectTaskType(filename){if(filename.includes("security-scan"))return"SECURITY";if(filename.includes("codebase-audit"))return"AUDIT";if(filename.includes("impact-"))return"IMPACT";if(filename.includes("darktheme-audit"))return"DARK-THEME";if(filename.includes("predeploy"))return"PRE-DEPLOY";if(filename.includes("tech-research"))return"RESEARCH";if(filename.includes("docs-"))return"DOCS";return"ANALYSIS"}function checkGeminiDaemon(){try{const PID_FILE=".claude/gemini-bridge/daemon.pid";if(!fs.existsSync(PID_FILE)){console.log("\n╔══════════════════════════════════════════╗");console.log("║   GEMINI AUTO-REVIEWER 데몬 미실행       ║");console.log("╚══════════════════════════════════════════╝");console.log("");console.log("자동 코드 리뷰를 위해 별도 터미널에서 실행하세요:");console.log("  bash .claude/hooks/start-gemini-daemon.sh");console.log("");console.log("──────────────────────────────────────────────\n");return}const pid=parseInt(fs.readFileSync(PID_FILE,"utf8").trim(),10);if(isNaN(pid)){console.log("\n⚠️  Gemini daemon PID file corrupt. Restart with:");console.log("  bash .claude/hooks/start-gemini-daemon.sh restart\n");return}try{process.kill(pid,0);console.log(`\n✅ Gemini auto-reviewer daemon running (PID: ${pid})\n`)}catch(e){if(e.code==="ESRCH"){console.log("\n╔══════════════════════════════════════════╗");console.log("║   GEMINI AUTO-REVIEWER 데몬 중단됨       ║");console.log("╚══════════════════════════════════════════╝");console.log("");console.log("데몬이 비정상 종료되었습니다. 재시작하세요:");console.log("  bash .claude/hooks/start-gemini-daemon.sh restart");console.log("");console.log("──────────────────────────────────────────────\n");try{fs.unlinkSync(PID_FILE)}catch(_){}}}}catch(_){}}checkGeminiDaemon();run();